What does this program print?

```cpp
#include <iostream>
int main() {
    int* p = new int{42};
    *p = *p * 2;
    std::cout << *p << "\n";
    delete p;
    p = nullptr;
    std::cout << (p == nullptr ? "null" : "valid") << "\n";
}
```

